<?php
namespace App\Domain\Equipment;use App\Domain\WorldCatalog\CatalogStatus;use App\Domain\WorldCatalog\ItemType;use App\Models\CharacterClass;use App\Models\Item;use Illuminate\Support\Collection;use InvalidArgumentException;
final class EquipmentRequirementValidator{public function validate(Item $item,Collection $classes){$level=(int)$item->required_level;if($level<1||$level>65535)throw new InvalidArgumentException('Required level must be between 1 and 65535.');if($item->item_type!==ItemType::EQUIPMENT&&($level!==1||$classes->isNotEmpty()))throw new InvalidArgumentException('Non-equipment Items cannot have equipment requirements.');return$item;}public function validateSelection(Collection $selected,Collection $historical){foreach($selected as $class)if($class->status!==CatalogStatus::ACTIVE&&!$historical->contains('id',$class->id))throw new InvalidArgumentException('Inactive classes cannot be added to equipment requirements.');}}
